import{_ as o,o as i,c as t,a2 as a}from"./chunks/framework.Bix3-HpO.js";const k=JSON.parse('{"title":"Review Page Blocks","description":"Kemoku Plugin - Review Page Blocks","frontmatter":{"title":"Review Page Blocks","description":"Kemoku Plugin - Review Page Blocks","weight":50,"extra":{"order":50},"head":[["link",{"rel":"canonical","href":"https://docs.dinomatic.com/docs/kemoku/review-page-blocks"}],["meta",{"property":"og:url","content":"https://docs.dinomatic.com/docs/kemoku/review-page-blocks"}],["meta",{"property":"og:title","content":"Review Page Blocks"}],["meta",{"property":"og:description","content":"Kemoku Plugin - Review Page Blocks"}],["meta",{"name":"twitter:title","content":"Review Page Blocks"}],["meta",{"name":"twitter:description","content":"Kemoku Plugin - Review Page Blocks"}]]},"headers":[],"relativePath":"docs/kemoku/review-page-blocks.md","filePath":"docs/kemoku/review-page-blocks.md"}'),s={name:"docs/kemoku/review-page-blocks.md"};function r(l,e,c,n,p,u){return i(),t("div",null,[...e[0]||(e[0]=[a('<h1 id="review-page-blocks" tabindex="-1">Review Page Blocks <a class="header-anchor" href="#review-page-blocks" aria-label="Permalink to &quot;Review Page Blocks&quot;">​</a></h1><p>There are multiple blocks and shortcodes available for you to present your website information. It is recommended to use native blocks instead of shortcodes, however if for some reason you&#39;re still using a version of WordPress lower than 5.0, you can use shortcodes as well.</p><p>There are 2 groups of blocks:</p><ol><li>Blocks you can use on all pages</li><li>Blocks you can use on review pages</li></ol><p>This page describes the blocks that you can use on review pages.</p><hr><h2 id="available-review-page-blocks" tabindex="-1">Available Review Page Blocks <a class="header-anchor" href="#available-review-page-blocks" aria-label="Permalink to &quot;Available Review Page Blocks&quot;">​</a></h2><p>Here are the blocks available in Kemoku plugin that you can use on any review page:</p><ul><li>Review Hero</li><li>Review Info</li><li>Review Ratings</li><li>Review Pros &amp; Cons</li><li>Review Payment Methods</li><li>Review Services</li><li>Review Countries</li><li>Review US States</li><li>Review Currencies</li><li>Review Sports</li><li>Review Country Support</li></ul><p>In most cases, there&#39;s nothing to configure in these blocks, simply add the blocks where you want to display them, and they are ready.</p><p>You can also use <strong><a href="/docs/kemoku/blocks#review-cta">Review CTA</a></strong> and <strong><a href="/docs/kemoku/blocks#review-bonus">Review Bonus</a></strong> blocks in review pages.</p><h3 id="review-hero-block" tabindex="-1">Review Hero Block <a class="header-anchor" href="#review-hero-block" aria-label="Permalink to &quot;Review Hero Block&quot;">​</a></h3><p><img src="https://media.dinomatic.com/images/docs/kemoku/review-hero-block.webp" alt="Kemoku Review Hero Block"></p><p>The Review Hero block displays the main hero section of your review page. This block doesn&#39;t require any configuration - it automatically displays the review information from your review fields.</p><h3 id="review-info-block" tabindex="-1">Review Info Block <a class="header-anchor" href="#review-info-block" aria-label="Permalink to &quot;Review Info Block&quot;">​</a></h3><p><img src="https://media.dinomatic.com/images/docs/kemoku/review-info-block.webp" alt="Kemoku Review Info Block"></p><p>The Review Info block displays the basic information about the reviewed item. This block doesn&#39;t require any configuration - it automatically displays the information from your review fields.</p><h3 id="review-ratings-block" tabindex="-1">Review Ratings Block <a class="header-anchor" href="#review-ratings-block" aria-label="Permalink to &quot;Review Ratings Block&quot;">​</a></h3><p><img src="https://media.dinomatic.com/images/docs/kemoku/review-ratings-block.webp" alt="Kemoku Review Ratings Block"></p><p>The Review Ratings block has 2 configuration options:</p><ul><li><strong>Display Option</strong>: Choose between &quot;Stars&quot; or &quot;Progress Bar&quot; display format</li><li><strong>Display a CTA Section</strong>: Toggle to show/hide the call-to-action section</li></ul><h3 id="review-pros-cons-block" tabindex="-1">Review Pros &amp; Cons Block <a class="header-anchor" href="#review-pros-cons-block" aria-label="Permalink to &quot;Review Pros &amp; Cons Block&quot;">​</a></h3><p><img src="https://media.dinomatic.com/images/docs/kemoku/review-pros-cons-block.webp" alt="Kemoku Review Pros &amp; Cons Block"></p><p>The Review Pros &amp; Cons block doesn&#39;t require any configuration, just make sure you have filled in the <code>Pros &amp; Cons</code> fields on review page.</p><h3 id="review-payment-methods-block" tabindex="-1">Review Payment Methods Block <a class="header-anchor" href="#review-payment-methods-block" aria-label="Permalink to &quot;Review Payment Methods Block&quot;">​</a></h3><p><img src="https://media.dinomatic.com/images/docs/kemoku/review-payment-methods-block.webp" alt="Kemoku Review Payment Methods Block"></p><p>The Review Payment Methods block has 1 configuration option:</p><ul><li><strong>Display a CTA Section</strong>: Toggle to show/hide the call-to-action section</li></ul><h3 id="review-services-block" tabindex="-1">Review Services Block <a class="header-anchor" href="#review-services-block" aria-label="Permalink to &quot;Review Services Block&quot;">​</a></h3><p><img src="https://media.dinomatic.com/images/docs/kemoku/review-services-block.webp" alt="Kemoku Review Services Block"></p><p>The Review Services block has 3 optional fields:</p><ul><li><strong>Block Heading</strong>: Leave empty for default heading, or set &quot;none&quot; for no heading.</li><li><strong>Bonus</strong>: Leave empty for default review bonus or add a new one.</li><li><strong>Button Text</strong>: Leave empty for default button text or set a custom one.</li></ul><h3 id="review-countries-block" tabindex="-1">Review Countries Block <a class="header-anchor" href="#review-countries-block" aria-label="Permalink to &quot;Review Countries Block&quot;">​</a></h3><p><img src="https://media.dinomatic.com/images/docs/kemoku/review-countries-block.webp" alt="Kemoku Review Countries Block"></p><p>The Review Countries block has 2 configuration options:</p><ul><li><strong>List Supported or Restricted Countries</strong>: Choose whether to display supported countries or restricted countries</li><li><strong>Display a CTA Section</strong>: Toggle to show/hide the call-to-action section</li></ul><h3 id="review-us-states-block" tabindex="-1">Review US States Block <a class="header-anchor" href="#review-us-states-block" aria-label="Permalink to &quot;Review US States Block&quot;">​</a></h3><p>The Review US States block has 2 configuration options:</p><ul><li><strong>Style</strong>: Choose between &quot;Map&quot; or &quot;List&quot; display format</li><li><strong>Display a CTA Section</strong>: Toggle to show/hide the call-to-action section</li></ul><p>This is the states displayed as a map.</p><p><img src="https://media.dinomatic.com/images/docs/kemoku/review-us-states-block.webp" alt="Kemoku Review US States Block"></p><p>This is the states displayed as a list. If you switch off the &quot;Display CTA section&quot; option, the part with the review item&#39;s logo will not be displayed.</p><p><img src="https://media.dinomatic.com/images/docs/kemoku/review-us-states-block.webp" alt="Kemoku Review US States Block"></p><h3 id="review-currencies-block" tabindex="-1">Review Currencies Block <a class="header-anchor" href="#review-currencies-block" aria-label="Permalink to &quot;Review Currencies Block&quot;">​</a></h3><p><img src="https://media.dinomatic.com/images/docs/kemoku/review-currencies-block.webp" alt="Kemoku Review Currencies Block"></p><p>The Review Currencies block has 1 configuration option:</p><ul><li><strong>Display a CTA Section</strong>: Toggle to show/hide the call-to-action section</li></ul><p>This is what the currencies block looks like. If you switch off the &quot;Display CTA section&quot; option, the part with the logo and link will not be displayed.</p><p>If you for some reason add a custom currency and no symbol, there will be a dash instead of it.</p><h3 id="review-sports-block" tabindex="-1">Review Sports Block <a class="header-anchor" href="#review-sports-block" aria-label="Permalink to &quot;Review Sports Block&quot;">​</a></h3><p><img src="https://media.dinomatic.com/images/docs/kemoku/review-sports-block.webp" alt="Kemoku Review Sports Block"></p><p>The Review Sports block has 1 configuration option:</p><ul><li><strong>Display a CTA Section</strong>: Toggle to show/hide the call-to-action section</li></ul><p>This is what the sports block looks like. If you switch off the &quot;Display CTA section&quot; option, the button will not be displayed.</p><h3 id="review-country-support-block" tabindex="-1">Review Country Support Block <a class="header-anchor" href="#review-country-support-block" aria-label="Permalink to &quot;Review Country Support Block&quot;">​</a></h3><p><img src="https://media.dinomatic.com/images/docs/kemoku/review-country-support-block.webp" alt="Kemoku Review Country Support Block"></p><p><code>💁 since version 2.0</code> The Review Country Support block displays geo-targeting information for the current review. This block doesn&#39;t require any configuration - it automatically shows country availability status based on the visitor&#39;s location and the review&#39;s supported countries.</p>',57)])])}const d=o(s,[["render",r]]);export{k as __pageData,d as default};
